struct TexturedBackground_Uniforms
{
	nCine::RhiSoftware::sw::vec2 uViewSize;
	nCine::RhiSoftware::sw::vec2 uCameraPos;
	nCine::RhiSoftware::sw::vec4 uHorizonColor;
	nCine::RhiSoftware::sw::vec2 uShift;
};

static nCine::RhiSoftware::sw::vec2 TexturedBackground_hash2D(const nCine::RhiSoftware::FragmentShaderInput& in, nCine::RhiSoftware::sw::vec2 p)
{
	using namespace nCine::RhiSoftware::sw;
	const TexturedBackground_Uniforms* unis = static_cast<const TexturedBackground_Uniforms*>(in.userData);
	(void)unis;
	(void)in;
	float h = dot(p, vec2(12.9898f, 78.233f));
	float h2 = dot(p, vec2(37.271f, 377.632f));
	return -1.0f + 2.0f * vec2(fract(sin(h) * 43758.5453f), fract(sin(h2) * 43758.5453f));
}

static nCine::RhiSoftware::sw::vec3 TexturedBackground_voronoi(const nCine::RhiSoftware::FragmentShaderInput& in, nCine::RhiSoftware::sw::vec2 p)
{
	using namespace nCine::RhiSoftware::sw;
	const TexturedBackground_Uniforms* unis = static_cast<const TexturedBackground_Uniforms*>(in.userData);
	(void)unis;
	(void)in;
	vec2 n = floor(p);
	vec2 f = fract(p);
	vec2 mg;
	vec2 mr;
	float md = 8.0f;
	for (int j = -1; j <= 1; ++j) {
		for (int i = -1; i <= 1; ++i) {
			vec2 g = vec2(float(i), float(j));
			vec2 o = TexturedBackground_hash2D(in, n + g);
			vec2 r = g + o - f;
			float d = dot(r, r);
			if (d < md) {
				md = d;
				mr = r;
				mg = g;
			}
		}
	}
	return vec3(md, mr);
}

static float TexturedBackground_addStarField(const nCine::RhiSoftware::FragmentShaderInput& in, nCine::RhiSoftware::sw::vec2 samplePosition, float threshold)
{
	using namespace nCine::RhiSoftware::sw;
	const TexturedBackground_Uniforms* unis = static_cast<const TexturedBackground_Uniforms*>(in.userData);
	(void)unis;
	(void)in;
	vec3 starValue = TexturedBackground_voronoi(in, samplePosition);
	if (starValue.x < threshold) {
		float power = 1.0f - starValue.x / threshold;
		return min(power * power * power, 0.5f);
	}
	return 0.0f;
}

void TexturedBackground_Fragment(const nCine::RhiSoftware::FragmentShaderInput& in)
{
	using namespace nCine::RhiSoftware::sw;
	const TexturedBackground_Uniforms* unis = static_cast<const TexturedBackground_Uniforms*>(in.userData);
	(void)unis;
	(void)in;
	vec4 COLOR;
	float distance = 1.3f - abs(2.0f * vec2(in.u, in.v).y - 1.0f);
	float horizonDepth = pow(distance, 1.4f);
	float yShift = vec2(in.u, in.v).y > 0.5f ? 1.0f : 0.0f;
	float correction = unis->uViewSize.x * 9.0f / (unis->uViewSize.y * 16.0f);
	vec2 texturePos = vec2(unis->uShift.x / 256.0f + (vec2(in.u, in.v).x - 0.5f) * (0.5f + 1.5f * horizonDepth) * correction, unis->uShift.y / 256.0f + (vec2(in.u, in.v).y - yShift) * 1.4f * distance);
	vec4 texColor = swTexture(in, 0, texturePos);
	float horizonOpacity = clamp(pow(distance, 1.5f) - 0.3f, 0.0f, 1.0f);
	vec4 horizonColorWithStars = vec4(unis->uHorizonColor.xyz(), 1.0f);
	if (unis->uHorizonColor.w > 0.0f) {
		vec2 samplePosition = vec2(in.u, in.v) * unis->uViewSize / unis->uViewSize.xx() + unis->uCameraPos.xy() * 0.00012f;
		horizonColorWithStars += vec4(TexturedBackground_addStarField(in, samplePosition * 7.0f, 0.00008f));
		samplePosition = vec2(in.u, in.v) * unis->uViewSize / unis->uViewSize.xx() + unis->uCameraPos.xy() * 0.00018f + 0.5f;
		horizonColorWithStars += vec4(TexturedBackground_addStarField(in, samplePosition * 7.0f, 0.00008f));
	}
	COLOR = mix(texColor, horizonColorWithStars, horizonOpacity);
	COLOR.a = 1.0f;
	packColor(COLOR, in.rgba);
}

